const d = $input.first().json?.body || $input.first().json;
const nome = d.nome || 'Cliente';
const primeiroNome = nome.split(' ')[0];
const telefone = d.telefone || '';
const email = d.email || '';
const empresa = d.empresa || '';
const interesse = d.interesse || 'juridico';
const interesseLabel = d.interesse_label || interesse;
const descricaoOutros = d.descricao_outros || '';
const tema = interesse === 'outros' ? (descricaoOutros || 'direito e tecnologia') : interesseLabel;
const geminiBody = JSON.stringify({
  model: 'gemini-2.5-flash',
  messages: [
    { role: 'system', content: 'Voce e o Teo, assistente juridico-filosofico da Fenice IT. Responda APENAS com o insight, sem introducao, sem aspas, sem markdown. Maximo 2 linhas.' },
    { role: 'user', content: 'Um prospect se interessou por: ' + tema + '. Gere 1 insight juridico ou filosofico surpreendente. Tom: inteligente, caloroso.' }
  ],
  max_tokens: 120,
  temperature: 0.8
});
return [{ json: { nome, primeiroNome, telefone, email, empresa, interesse, interesseLabel, descricaoOutros, tema, geminiBody } }];

const dados = $('2. Preparar Dados + Prompt Gemini').first().json;
const geminiResp = $input.first().json;
let wowInsight = 'A Fenice IT combina IA, filosofia e direito para entregar o que nenhuma LegalTech brasileira oferece.';
try {
  const msg = geminiResp?.choices?.[0]?.message?.content;
  if (msg && msg.length > 10) wowInsight = msg.trim();
} catch(e) {}
return [{ json: { ...dados, wowInsight } }];

